using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace McpServer.Tools;

[McpServerToolType]
public class ApiTools
{
    [McpServerTool, Description("Fetches data from an external API endpoint and returns the JSON response.")]
    public static async Task<string> FetchApiData(
        IHttpClientFactory httpClientFactory,
        [Description("The full URL of the API endpoint to call.")] string url,
        CancellationToken cancellationToken = default)
    {
        using var client = httpClientFactory.CreateClient("api");

        var response = await client.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(
            await response.Content.ReadAsStreamAsync(cancellationToken),
            cancellationToken: cancellationToken);

        return JsonSerializer.Serialize(doc, new JsonSerializerOptions { WriteIndented = true });
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpServer.Prompts;

[McpServerPromptType]
public class SummarizationPrompts
{
    [McpServerPrompt, Description("Generates a prompt that asks an LLM to summarize the provided text.")]
    public static IEnumerable<ChatMessage> Summarize(
        [Description("The text content to summarize.")] string text,
        [Description("Optional desired length: short, medium, or detailed.")] string length = "medium")
    {
        yield return new ChatMessage(
            ChatRole.User,
            $$"""
            Summarize the following text. Target length: {{length}}.

            ---
            {{text}}
            ---

            Provide a clear, concise summary that captures the key points.
            """);
    }
}

